const m = $json;
const headers = (m.payload && m.payload.headers) || [];
const h = (n) => ((headers.find(x => (x.name||'').toLowerCase() === n) || {}).value) || '';
const from = m.From || m.from || h('from');
const match = from.match(/<([^>]+)>/);
const senderEmail = (match ? match[1] : from).trim().toLowerCase();
const subject = m.Subject || m.subject || h('subject');
const body = m.text || m.textPlain || m.snippet || '';
return [{ json: { senderEmail, subject, body, threadId: m.threadId, messageId: m.id } }];

const found = ($json.records || []);
if (!found.length) return []; // unknown sender -> ignore (not a tracked lead)
const c = found[0];
const ex = $('Extract Message').item.json;
return [{ json: { companyId: c.id, companyName: c.fields.Name, senderEmail: ex.senderEmail, subject: ex.subject, latest: ex.body, threadId: ex.threadId, messageId: ex.messageId } }];

const recs = ($json.records || []).map(r => r.fields);
const ctx = $('Build Context').item.json;
const hist = recs.map(f => `[${f.Direction||'?'}] ${f.Subject||''}\n${f.Body||''}`).join('\n---\n');
return [{ json: { ...ctx, historyText: hist || '(no prior messages logged)' } }];

