const txt = $json.content?.[0]?.text || '{}';
let r = {};
try { r = JSON.parse(txt); } catch (e) {
  const m = txt.match(/\{[\s\S]*\}/); if (m) { try { r = JSON.parse(m[0]); } catch(_){} }
}
const statuses = ['Replied','Negotiating','Won','Lost'];
return [{ json: {
  language: r.language || 'en',
  intent: r.intent || 'Other',
  message_summary: r.message_summary || '',
  action_items: Array.isArray(r.action_items) ? r.action_items.join('; ') : '',
  recommended_status: statuses.includes(r.recommended_status) ? r.recommended_status : 'Replied',
  needs_human_review: r.needs_human_review === true,
  subject: r.subject || ('Re: ' + ($('Build Context').item.json.subject || '')),
  body: (r.body || '') + '\n\n' + ($env.SENDER_SIGNATURE || '').replace(/\\n/g,'\n')
}}];
